mapper.select:
SELECT l.id, l.employee_id, l.leave_type, l.start_time, l.end_time, l.days, l.reason, l.status, l.created_at, l.updated_at, e.employee_no, e.name AS employee_name, d.department_name FROM leave_record l INNER JOIN employee e ON l.employee_id = e.id LEFT JOIN department d ON e.department_id = d.id
AND e.status = '在职' AND l.status != '已取消'
AND e.employee_no = #{employeeNo}
AND e.name LIKE CONCAT('%', #{name}, '%')
AND e.department_id = #{departmentId}
AND DATE(l.start_time) >= #{startDate}
AND DATE(l.end_time) <= #{endDate}
ORDER BY l.start_time DESC, l.id DESC

SELECT id, employee_id, leave_type, start_time, end_time, days, reason, status, created_at, updated_at
FROM leave_record
WHERE id = #{id}

mapper.update:
UPDATE leave_record
SET status = '已取消'
WHERE id = #{id}
